xmcp.oas.datatype.OASValidationResult result = new xmcp.oas.datatype.OASValidationResult();
result.setErrorMessages(new ArrayList<String>());
// validate TestMeasure.accuracy of type Double
try {
    var validator_accuracy = new com.gip.xyna.openapi.NumberTypeValidator<Double>();
    validator_accuracy.setName("accuracy");
    validator_accuracy.setValue(getAccuracy());
    validator_accuracy.setFormat("float");
    result.getErrorMessages().addAll(validator_accuracy.checkValid());
} catch (Exception e) {
    result.getErrorMessages().add("Error: could not validate TestMeasure.accuracy");
}

